import React, { useRef, useState } from 'react';
import 'react-tabs/style/react-tabs.css';
import cls from './CheckoutPage.module.scss';
import { CardElement, useElements, useStripe } from '@stripe/react-stripe-js';
import Button from '../../common/UI/Button/Button';
import { useNavigate, useLocation } from 'react-router-dom';
import { subscriptionPayment, servicesPayment } from '../../../services/payments.service';
import { getCompanyDetails } from '../../../services/company.service';
import { first } from 'rxjs';
import { ModalR, RenderTitle, SelectWithSearch } from '../../common';
import { arrowDown, chevron, dropDownArrow, partyCircle } from '../../../assets/images/icons';
import { leftArrow } from '../../../assets/images/new-icons';
import { country_list } from '../../../shared/utility';
import PhoneInput from 'react-phone-input-2';
import 'react-phone-input-2/lib/material.css';
import { date } from 'yup';
import moment, { now } from 'moment';

function CheckoutPage() {
	const form = useRef();
	const [firstName, setFirstName] = useState('');
	const [lastName, setLastName] = useState('');
	const [address, setAddress] = useState('');
	const [city, setCity] = useState('');
	const [postalCode, setPostalCode] = useState('');
	const [country, setCountry] = useState('');
	const [state, setState] = useState('');
	const [vat, setVat] = useState('');
	const [mobile, setMobile] = useState('');
	const [cardName, setCardName] = useState('');
	const [loading, setLoading] = useState(false);
	const [errorMsg, setErrorMsg] = useState('');
	const [subscriptionDone, setSubscriptionDone] = useState(false);
	const [paymentReference, setPaymentReference] = useState('');
	const [formHide, setFormHide] = useState(true);
	const stripe = useStripe();
	const elements = useElements();
	const location = useLocation();

	const hasBillingInformation = () => {
		return !formHide && (firstName !== '' || lastName !== '' || address !== '' || city !== '' || postalCode !== '' || country !== '' || state !== '' || vat !== '' || mobile !== '');
	};

	const isCompleteBillingInformation = () => {
		return !(firstName === '' || lastName === '' || address === '' || city === '' || postalCode === '' || country === '' || state === '' || vat === '' || mobile === '');
	};

	const handleServicesSubmit = () => {
		setErrorMsg('');
		setLoading(true);

		servicesPayment(location.state.service_name, location.state.price.price_code, location.state.price.duration ?? null)
			.pipe(first())
			.subscribe({
				next: data => {
					setPaymentReference(data.data.stripe_id);
					setSubscriptionDone(true);
					getCompanyDetails().pipe(first()).subscribe({});
					setLoading(false);
				},
				error: error => {
					if (error.data != undefined) {
						setErrorMsg(error.data.message.message);
					} else {
						setErrorMsg('Payment error. Please check your card.');
					}

					setLoading(false);
				},
			});
	};

	const handleSubmit = async event => {
		setErrorMsg('');

		if (cardName === '') {
			setErrorMsg('Please enter card owner name.');
			return;
		}
		// We don't want to let default form submission happen here,
		// which would refresh the page.
		event.preventDefault();

		if (!stripe || !elements) {
			// Stripe.js has not yet loaded.
			// Make sure to disable form submission until Stripe.js has loaded.
			return;
		}

		setLoading(true);
		setErrorMsg('');

		if (hasBillingInformation() && !isCompleteBillingInformation()) {
			let errors = [];
			if (firstName === '') {
				errors.push('first name');
			}
			if (lastName === '') {
				errors.push('last name');
			}
			if (address === '') {
				errors.push('full address');
			}
			if (city === '') {
				errors.push('city');
			}
			if (postalCode === '') {
				errors.push('postal Code');
			}
			if (country === '') {
				errors.push('country');
			}
			if (vat === '') {
				errors.push('VAT/TAX ID');
			}
			if (mobile === '') {
				errors.push('phone Number');
			}

			if (errors.length > 1) {
				errors = errors.map((error, index) => <li key={index}>{error}</li>);
				let ErrorMsg = () => (
					<>
						<span>Please fill in all input fields:</span>
						<ul>{errors}</ul>
					</>
				);
				setLoading(false);
				setErrorMsg(ErrorMsg);
				return;
			}
			setLoading(false);
			setErrorMsg(`Please enter ${errors[0]}`);
			return;
		}

		const getBillingDetails = () => {
			if (hasBillingInformation()) {
				return {
					name: firstName + ' ' + lastName,
					address: {
						city: city,
						country: country,
						line1: address,
						postal_code: postalCode,
						state: state,
					},
					phone: mobile,
					email: location.state.companyData.email,
				};
			}
			return {};
		};

		const paymentMethodObj = {
			type: 'card',
			card: elements.getElement(CardElement),
			billing_details: getBillingDetails(),
		};

		const paymentMethodResult = await stripe.createPaymentMethod(paymentMethodObj);
		if (paymentMethodResult.error !== undefined) {
			setLoading(false);
			setErrorMsg(paymentMethodResult.error?.message ?? 'Invalid card details');
			return;
		}
		//console.log(paymentMethodResult);

		// subscriptionPayment(location.state.companyData.billable_users, location.state.subscriptionInfo.price_code, paymentMethodResult.paymentMethod?.id)
		// 	.pipe(first())
		// 	.subscribe({
		// 		next: data => {
		// 			if (data.message === 'Add Subscription successful') {
		// 				setPaymentReference(data.data.stripe_id);
		// 				setSubscriptionDone(true);
		// 				getCompanyDetails().pipe(first()).subscribe({});
		// 			}
		// 		},
		// 		complete: () => {},
		// 		error: error => {
		// 			if (error.data != undefined) {
		// 				setErrorMsg(error.data.message.message);
		// 			} else {
		// 				setErrorMsg('Payment error. Please check your card');
		// 			}

		// 			setLoading(false);
		// 		},
		// 	});
	};

	return (
		<div className={cls.checkoutPageHost}>
			<div className={cls.checkoutTop}>
				<Button clicked={() => window.history.back()} title={'Back'} />
			</div>
			<div className={cls.checkoutContent}>
				<div className={cls.checkoutLeftContainer} style={{ display: location.state.subscriptionInfo ? '' : 'none' }}>
					<p className={cls.pageTitle}>Complete your Purchase</p>
					<p className={cls.sectionTitle} style={{ marginTop: '0px' }}>
						Payment Information
					</p>
					<div className={cls.inputRow}>
						<div className={cls.inputContainer}>
							<RenderTitle title={'Name on Card *'} />
							<input value={cardName} onChange={e => setCardName(e.target.value)} type="text" name="state" className={cls.inputField} />
						</div>
					</div>
					<div className={cls.inputRow}>
						<div className={cls.inputContainer}>
							<RenderTitle title={'Card Number *'} />

							<CardElement id="cc-number" className={cls.stripeCardNumberContainer} />
						</div>
					</div>
					<p className={cls.sectionTitle} style={{ marginTop: '0px' }}>
						Invoicing Information
						<span style={{ cursor: 'pointer' }}>
							<img alt={''} src={chevron} style={{ marginLeft: '10px', marginBottom: '3px', transform: formHide === true ? 'rotate(180deg)' : 'rotate(0deg)' }} onClick={() => setFormHide(!formHide)} />
						</span>
					</p>
					<form ref={form} style={{ display: formHide === true ? 'none' : '' }}>
						<div className={cls.inputRow}>
							<div className={cls.inputContainer}>
								<RenderTitle title={'First Name'} />
								<input value={firstName} onChange={e => setFirstName(e.target.value)} style={{ marginRight: '30px' }} type="text" name="first-name" className={cls.inputField} />
							</div>
							<div className={cls.inputContainer}>
								<RenderTitle title={'Last Name'} />
								<input value={lastName} onChange={e => setLastName(e.target.value)} type="text" name="last-name" className={cls.inputField} />
							</div>
						</div>
						<div className={cls.inputRow}>
							<div className={cls.inputContainer}>
								<RenderTitle title={'Full Address'} />
								<input value={address} onChange={e => setAddress(e.target.value)} style={{ marginRight: '30px' }} type="text" name="full-address" className={cls.inputField} />
							</div>
						</div>
						<div className={cls.inputRow}>
							<div className={cls.inputContainer}>
								<RenderTitle title={'City'} />
								<input value={city} onChange={e => setCity(e.target.value)} style={{ marginRight: '30px' }} type="text" name="city" className={cls.inputField} />
							</div>
							<div className={cls.inputContainer}>
								<RenderTitle title={'Postal Code'} />
								<input value={postalCode} onChange={e => setPostalCode(e.target.value)} type="text" name="postal-code" className={cls.inputField} />
							</div>
						</div>
						<div className={cls.inputRow}>
							<div className={cls.inputContainer}>
								<RenderTitle title={'Country'} />
								<SelectWithSearch
									items={country_list}
									triggerType={'chevron'}
									onChange={selection => {
										setCountry(selection.value);
									}}
									className={cls.currencySelectContainer}
									inputClassName={cls.currencySearchInput}
									clearControlsClassName={cls.currencyClearControlsClassName}
									molclassname={cls.currencySelectMenuOverlayList}
									moliclassname={cls.currencySelectMenuOverlayListItem}
								/>
							</div>
							<div className={cls.inputContainer}>
								<RenderTitle title={'State'} />
								<input value={state} onChange={e => setState(e.target.value)} type="text" name="state" className={cls.inputField} />
							</div>
						</div>
						<div className={cls.inputRow}>
							<div className={cls.inputContainer}>
								<RenderTitle title={'VAT/TAX ID'} />

								<input value={vat} onChange={e => setVat(e.target.value)} style={{ marginRight: '30px' }} type="text" name="vat" className={cls.inputField} />
							</div>
							<div className={cls.inputContainer}>
								<RenderTitle title={'Phone'} />

								<div className={cls.phoneContainer}>
									<PhoneInput country={'au'} value={mobile} onChange={e => setMobile(e)} inputClass={cls.phoneIInput} specialLabel={''} placeholder={'Enter number here...'} inputStyle={{ border: 'none', width: '100%' }} />
								</div>
							</div>
						</div>
					</form>
				</div>
				<div className={cls.checkoutRightContainer}>
					<div className={cls.productsContainer}>
						<p className={cls.products}>Products</p>
						<div className={cls.planContainer}>
							<div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '10px' }}>
								{location.state.subscriptionInfo ? <p className={cls.planTitle}>{location.state.subscriptionInfo.plan} Plan</p> : <p className={cls.planTitle}>{location.state.price.description}</p>}
								{location.state.subscriptionInfo ? (
									<p className={cls.price}>{location.state.subscriptionInfo.plan_price}</p>
								) : (
									<p className={cls.price}>
										{location.state.price.currency} {location.state.price.price}
									</p>
								)}
							</div>
							<div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '5px', marginBottom: '5px' }}>
								{location.state.subscriptionInfo && <p className={cls.planDetails}>{location.state.companyData.billable_users} employees</p>}
								{location.state.subscriptionInfo && <p className={cls.priceDetails}>/month</p>}
							</div>
						</div>
						<hr style={{ borderTop: '1px solid #D2D2D2', margin: '5%' }} />
						<div style={{ display: location.state.companyData?.billable_users === undefined ? 'none' : 'flex', justifyContent: 'space-between', margin: '5%', marginBottom: '0px' }}>
							<p className={cls.planTitle}>Total Number of Employees</p>

							<p className={cls.price}>{location.state.companyData?.billable_users}</p>
						</div>
						<div style={{ display: 'flex', justifyContent: 'space-between', margin: '5%', marginBottom: '0px', marginTop: '-20px' }}>
							<p className={cls.planTitle}>{'Taxes (if any)'}</p>

							<p className={cls.price}>{location.state.subscriptionInfo?.taxes ?? '$0'}</p>
						</div>

						<div style={{ display: 'flex', justifyContent: 'space-between', margin: '5%', marginBottom: '20px' }}>
							<p className={cls.planTitleBlue}>Total (due today)</p>
							{location.state.subscriptionInfo ? (
								<p className={cls.planTitleBlue}>{location.state.subscriptionInfo?.total}</p>
							) : (
								<p className={cls.planTitleBlue}>
									{location.state.price.currency} {location.state.price.price}
								</p>
							)}
						</div>
						<Button className={cls.payButton} disabled={loading} title={'Pay Now'} clicked={location.state.subscriptionInfo ? handleSubmit : handleServicesSubmit} loading={loading} />
						<div className={cls.endingMessage} style={{ display: location.state.companyData?.billable_users === undefined ? 'none' : '' }}>
							<p>{`You can cancel your plan anytime. Your yearly recurrent payment starts on ${moment(new Date(now())).add(1, 'years').format('MMMM Do, YYYY')}. You will be billed monthly for the number of Employees in your account.`}</p>
						</div>

						<div style={{ display: 'flex', justifyContent: 'space-between', margin: '5%', marginBottom: '0px', color: 'red' }}>{errorMsg && <div>{errorMsg}</div>}</div>
					</div>
				</div>
			</div>
			{subscriptionDone && <RenderCompletedModal message={paymentReference} />}
		</div>
	);
}

export default CheckoutPage;

const RenderCompletedModal = props => {
	const navigate = useNavigate();
	const { setCompletedModal, message } = props;

	return (
		<ModalR isOpen={true} shadowedContainerStyle={{ width: '35%', minWidth: '500px', minHeight: '400px' }} onClose={() => setCompletedModal(false)} scrollable={true} blured={true}>
			<div
				style={{
					display: 'flex',
					flexDirection: 'column',
					alignItems: 'center',
				}}
			>
				<img alt={''} src={partyCircle} />
				<p
					style={{
						marginTop: '10px',
						fontFamily: 'var(--app-font-gt-walsheim-pro)',
						fontSize: '32px',
						color: '#4A4A4A',
						marginBottom: '5px',
						textAlign: 'center',
					}}
				>
					{'Your subscription to FlowHero was successful!'}
				</p>
				<p
					style={{
						width: '300px',
						fontFamily: 'var(--app-font-quicksand-medium)',
						fontSize: '16px',
						color: '#4A4A4A',
						textAlign: 'center',
						marginBottom: '20px',
					}}
				>
					{`Your payment reference is ${message}`}
					<br />
					<br />
					{'You can look for this in your invoices list in the billing page '}
					<br />
					<br />
					<span style={{ fontWeight: '700' }}>{'Great Job!'}</span>
				</p>
				<Button
					style={{ width: '200px' }}
					clicked={() => {
						navigate('/billing-info');
					}}
					title={'View Invoices'}
				/>
			</div>
		</ModalR>
	);
};
